package main
import("bytes";"encoding/json";"io";"net/http";"os";"strings";"github.com/go-chi/chi/v5";"github.com/google/uuid")
func post(url string,body any,auth string)(map[string]any,error){b,_:=json.Marshal(body);req,_:=http.NewRequest("POST",url,bytes.NewReader(b));req.Header.Set("Content-Type","application/json");if auth!=""{req.Header.Set("Authorization",auth)};resp,err:=http.DefaultClient.Do(req);if err!=nil{return nil,err};defer resp.Body.Close();m:=map[string]any{};json.NewDecoder(resp.Body).Decode(&m);return m,nil}
func main(){r:=chi.NewRouter();r.Get("/health",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("ok"))});r.Get("/metrics",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("gateway_up 1"))});r.Post("/v1/chat/completions",func(w http.ResponseWriter,r *http.Request){auth:=r.Header.Get("Authorization");key:=strings.TrimPrefix(auth,"Bearer ");var req map[string]any;json.NewDecoder(r.Body).Decode(&req);v,_:=post("http://auth:8086/validate",map[string]any{"api_key":key},"");uid:=int(v["user_id"].(float64));model:=req["model"].(string);_,_=post("http://wallet:8082/hold",map[string]any{"user_id":uid,"amount":1.0,"ref_id":uuid.NewString()},"");sch,_:=post("http://scheduler:8081/schedule",map[string]any{"user_id":uid},"");nodeID:=sch["node_id"].(string);rid:=uuid.NewString();_,_=post("http://billing:8083/charge",map[string]any{"request_id":rid,"user_id":uid,"node_id":nodeID,"model":model,"input_tokens":100,"output_tokens":20},"");_,_=post("http://wallet:8082/capture",map[string]any{"user_id":uid,"amount":0.0096,"ref_id":rid},"");_,_=post("http://settlement:8087/earnings",map[string]any{"request_id":rid,"node_id":nodeID,"amount":0.0096},"");if s,ok:=req["stream"].(bool);ok&&s{w.Header().Set("Content-Type","text/event-stream");io.WriteString(w,"data: {\"id\":\"chatcmpl-1\",\"choices\":[{\"delta\":{\"content\":\"hello\"}}]}\n\n");io.WriteString(w,"data: [DONE]\n\n");return};json.NewEncoder(w).Encode(map[string]any{"id":"chatcmpl-1","object":"chat.completion","choices":[]any{map[string]any{"message":map[string]any{"role":"assistant","content":"hello from hypercompute"}}}})});http.ListenAndServe(":"+getenv("PORT","8080"),r)}
func getenv(k,d string)string{v:=os.Getenv(k);if v==""{return d};return v}
